// -------------------------------------------------------
// NODE: Extract Resume Text
// Decodes the uploaded PDF binary and extracts readable
// text from it using basic PDF text stream parsing.
// Works for standard text-based PDFs.
// -------------------------------------------------------

const item = $input.item;

const email = item.json['Email Address'];
const jobDescription = item.json['Job Description'];

const fileKey = Object.keys(item.binary || {})[0];
if (!fileKey) {
  throw new Error('No resume file found in the submission.');
}

const fileBinary = item.binary[fileKey];
const buffer = Buffer.from(fileBinary.data, 'base64');

// Extract text from PDF by parsing raw content streams
// This works for standard text-based PDFs without needing external libraries
let pdfText = '';
const pdfString = buffer.toString('binary');

// Extract text between BT (begin text) and ET (end text) markers
const textBlocks = pdfString.match(/BT[\s\S]*?ET/g) || [];

for (const block of textBlocks) {
  // Extract text from Tj and TJ operators
  const tjMatches = block.match(/\(([^)]+)\)\s*Tj/g) || [];
  const tjArrayMatches = block.match(/\[([^\]]+)\]\s*TJ/g) || [];

  for (const match of tjMatches) {
    const text = match.replace(/\(([^)]+)\)\s*Tj/, '$1');
    pdfText += text + ' ';
  }

  for (const match of tjArrayMatches) {
    const strings = match.match(/\(([^)]+)\)/g) || [];
    for (const s of strings) {
      pdfText += s.replace(/[()]/g, '') + ' ';
    }
  }
}

// Clean up the extracted text
pdfText = pdfText
  .replace(/\\n/g, '\n')
  .replace(/\\t/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

if (!pdfText || pdfText.length < 50) {
  throw new Error('Could not extract readable text from the PDF. The file may be image-based or encrypted. Please upload a standard text-based PDF.');
}

return {
  email,
  jobDescription,
  resumeText: pdfText,
  resumeBase64: fileBinary.data
};

// -------------------------------------------------------
// NODE: Extract Resume Output
// Pulls the rewritten resume text from the AI Agent
// response and carries context fields forward.
// -------------------------------------------------------

const agentOutput = $input.item.json.output;

if (!agentOutput) {
  throw new Error('Resume Generator Agent did not return output. Check the agent node and Anthropic credential.');
}

const extractNode = $('Extract Resume Text').item.json;

return {
  email: extractNode.email,
  jobDescription: extractNode.jobDescription,
  rewrittenResume: agentOutput
};

// -------------------------------------------------------
// NODE: Prepare Overleaf Payload
// Extracts LaTeX from agent response, strips any markdown
// artifacts, validates it, generates a unique project name.
// -------------------------------------------------------

const agentOutput = $input.item.json.output;

if (!agentOutput) {
  throw new Error('LaTeX Converter Agent did not return output.');
}

let latexCode = agentOutput;

// Strip any markdown fences Claude might add
latexCode = latexCode.replace(/```latex/gi, '').replace(/```/g, '').trim();

// Validate it is actually LaTeX
if (!latexCode.includes('\\documentclass')) {
  throw new Error('Output does not contain valid LaTeX. Check the LaTeX Converter Agent prompt.');
}

const extractNode = $('Extract Resume Output').item.json;
const timestamp = Date.now();

return {
  latexCode,
  email: extractNode.email,
  projectName: `Resume_${timestamp}`
};

// -------------------------------------------------------
// NODE: Extract CSRF Token
// Parses Overleaf HTML to find the CSRF token.
// Required for all POST requests to Overleaf.
// -------------------------------------------------------

const body = $input.item.json.body;

if (!body) {
  throw new Error('No response from Overleaf. OVERLEAF_SESSION may have expired.');
}

let csrfToken = null;

const jsonMatch = body.match(/"csrfToken"\s*:\s*"([^"]+)"/);
if (jsonMatch) csrfToken = jsonMatch[1];

if (!csrfToken) {
  const metaMatch = body.match(/<meta\s+name="csrf-token"\s+content="([^"]+)"/);
  if (metaMatch) csrfToken = metaMatch[1];
}

if (!csrfToken) {
  const windowMatch = body.match(/window\.csrfToken\s*=\s*['"]([^'"]+)['"]/);
  if (windowMatch) csrfToken = windowMatch[1];
}

if (!csrfToken) {
  throw new Error('Could not extract CSRF token. Session may be invalid.');
}

const payload = $('Prepare Overleaf Payload').item.json;

return {
  csrfToken,
  latexCode: payload.latexCode,
  email: payload.email,
  projectName: payload.projectName
};

// -------------------------------------------------------
// NODE: Extract Project ID
// Pulls the project ID from the Overleaf creation response.
// -------------------------------------------------------

const response = $input.item.json;
let projectId = null;

if (response.body) {
  try {
    const parsed = typeof response.body === 'string' ? JSON.parse(response.body) : response.body;
    projectId = parsed.project_id || parsed._id || parsed.id;
  } catch(e) {
    projectId = response.body.project_id || response.body._id || response.body.id;
  }
}

if (!projectId && response.headers && response.headers.location) {
  const match = response.headers.location.match(/\/project\/([a-f0-9]+)/);
  if (match) projectId = match[1];
}

if (!projectId) {
  throw new Error('Could not extract project ID from Overleaf response.');
}

const prev = $('Extract CSRF Token').item.json;

return {
  projectId,
  csrfToken: prev.csrfToken,
  latexCode: prev.latexCode,
  email: prev.email
};

// -------------------------------------------------------
// NODE: Build Paste LaTeX Body
// Constructs the request body for pasting LaTeX into
// the Overleaf project safely without JSON interpolation issues.
// -------------------------------------------------------

const projectId = $input.item.json.projectId;
const csrfToken = $input.item.json.csrfToken;
const latexCode = $input.item.json.latexCode;
const email = $input.item.json.email;

const body = JSON.stringify({
  _csrf: csrfToken,
  name: 'main.tex',
  content: latexCode
});

return {
  projectId,
  csrfToken,
  email,
  body
};

// -------------------------------------------------------
// NODE: Check Compile Status
// Validates compilation succeeded and gets PDF path.
// -------------------------------------------------------

const response = $input.item.json;

let status = null;
let outputFiles = [];

try {
  const body = typeof response === 'string' ? JSON.parse(response) : response;
  status = body.status;
  outputFiles = body.outputFiles || [];
} catch(e) {
  throw new Error('Could not parse compile response.');
}

if (status !== 'success') {
  throw new Error(`Overleaf compilation failed: ${status}. Check LaTeX output.`);
}

const pdfFile = outputFiles.find(f => f.path && f.path.endsWith('.pdf'));
if (!pdfFile) {
  throw new Error('No PDF found in compile output.');
}

const projectData = $('Extract Project ID').item.json;

return {
  projectId: projectData.projectId,
  pdfBuild: pdfFile.build || '',
  email: projectData.email
};

// -------------------------------------------------------
// NODE: Prepare Email
// Renames the PDF binary and structures data for Gmail.
// -------------------------------------------------------

const item = $input.item;
const email = $('Check Compile Status').item.json.email;
const fileName = `Tailored_Resume_${Date.now()}.pdf`;

const binaryKey = Object.keys(item.binary || {})[0];
if (!binaryKey) {
  throw new Error('No PDF binary found. Check Download Resume PDF node.');
}

return {
  json: {
    recipientEmail: email,
    fileName
  },
  binary: {
    resumePDF: {
      ...item.binary[binaryKey],
      fileName,
      mimeType: 'application/pdf'
    }
  }
};
